use actix_web::{web, App, HttpServer, HttpResponse, Result, http::header, fs::NamedFile};
use std::path::{Path, PathBuf};

async fn serve_file(path: web::Path<String>) -> Result<HttpResponse> {
    let file_path = Path::new("uploads").join(&*path);
    
    if file_path.starts_with("uploads") && file_path.exists() && file_path.is_file() {
        let response = NamedFile::open(file_path)?
            .set_header(header::CacheControl(vec![header::CacheControlDirective::NoCache]))
            .into_response(&web::HttpRequest::default());
        Ok(response)
    } else {
        Ok(HttpResponse::NotFound().finish())
    }
}

#[actix_web::main]
async fn main() -> std::io::Result<()> {
    HttpServer::new(|| {
        App::new()
            .route("/{filename}", web::get().to(serve_file))
    })
    .bind("127.0.0.1:8080")?
    .run()
    .await
}